12	import type { Action, OnboardingState, Stage } from "../state/types";
13	import type {
14	  OnboardingStage,
15	  PersonalizationData,
16	  StagePayloads,
17	} from "../types/websocket";
18	
19	const MAX_RECONNECT_ATTEMPTS = 10;
20	const RECONNECT_BASE_DELAY_MS = 1000;
21	// If the WS connects but stays silent past this window, kick off a REST
22	// poll so the user isn't stuck behind a silent socket.
23	const WS_SILENCE_FALLBACK_MS = 5000;
24	// Once polling, refetch the snapshot at this cadence. Cleared the moment
25	// any WS event lands.
26	const POLL_INTERVAL_MS = 3000;
27	
28	function getWsUrl(): string {
29	  const base =
30	    process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:8000/api/v1/";
31	  return (
32	    base.replace("http://", "ws://").replace("https://", "wss://") +
33	    "ws/connect"
34	  );
35	}
36	
37	/**
38	 * Discriminated-union envelope: narrowing on `stage` automatically narrows
39	 * `payload`, so handlers can be typed without per-case `as` casts.
40	 */
41	type StageEnvelope = {
42	  [K in OnboardingStage]: { stage: K; payload: StagePayloads[K] };
43	}[OnboardingStage];
44	
45	/**
46	 * Activates once the user is past Q&A/focus. Fetches `/personalization`
47	 * once, then routes WS `onboarding_stage` events into reducer dispatches.
48	 * If the socket connects but stays silent for `WS_SILENCE_FALLBACK_MS`,
49	 * starts polling `/personalization` every `POLL_INTERVAL_MS` until the WS
50	 * sends an event or a snapshot with a conversation id arrives. Reconnects
51	 * with exponential backoff up to MAX_RECONNECT_ATTEMPTS.
52	 */
53	export function useBackendSync(
54	  state: OnboardingState,
55	  stage: Stage,
56	  dispatch: Dispatch<Action>,
57	): void {
58	  // Active once we've moved past the Q&A composer stages.
59	  const active =
60	    stage !== "questions" && stage !== "focus" && !state.isRestarting;
61	
62	  const dispatchRef = useRef(dispatch);
63	  const isRestartingRef = useRef(state.isRestarting);
64	
65	  useEffect(() => {
66	    dispatchRef.current = dispatch;
67	  });
68	  useEffect(() => {
69	    isRestartingRef.current = state.isRestarting;
70	  });
71	
72	  useEffect(() => {
73	    if (!active) return;
74	
75	    let aborted = false;
76	    let snapshotResolved = false;
77	    const buffer: StageEnvelope[] = [];
78	    let ws: WebSocket | null = null;
79	    let reconnectAttempts = 0;
80	    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
81	    let silenceTimer: ReturnType<typeof setTimeout> | null = null;
82	    let pollTimer: ReturnType<typeof setInterval> | null = null;
83	    let silenceFallbackUsed = false;
84	    let wsReceivedEvent = false;
85	    let closed = false;
86	
87	    type StageHandlers = {
88	      [K in OnboardingStage]: (payload: StagePayloads[K]) => void;
89	    };
90	
91	    const dispatchProgress = (
92	      stage: OnboardingStage,
93	      status_text: string | undefined,
94	    ): void => {
95	      if (!status_text) {
96	        console.warn(
97	          `[onboarding:ws] ${stage} progress event with no status_text — backend likely stale`,
98	        );
99	        return;
100	      }
101	      dispatchRef.current({ type: "progress", stage, message: status_text });
102	    };
103	
104	    const handlers: StageHandlers = {
105	      inbox_scanning: (p) => dispatchProgress("inbox_scanning", p.status_text),
106	      writing_style_progress: (p) =>
107	        dispatchProgress("writing_style_progress", p.status_text),
108	      triage_analyzing: (p) =>
109	        dispatchProgress("triage_analyzing", p.status_text),
110	      todos_creating: (p) => dispatchProgress("todos_creating", p.status_text),
111	      workflows_creating: (p) =>
112	        dispatchProgress("workflows_creating", p.status_text),
113	      writing_style_ready: (p) => {
114	        // For Gmail users where learning failed (LLM error, near-zero sent
115	        // emails) the backend still emits with style_summary=null so the
116	        // cursor can advance. Combined with `completedStages.has(
117	        // "writing_style_ready")`, derive.ts treats this as "skip the
118	        // reveal" instead of leaving the user stuck.
119	        const summary = p.style_summary?.trim();
120	        dispatchRef.current({
121	          type: "serverPatch",
122	          patch: {
123	            writing_style: summary
124	              ? { style_summary: summary, example: p.example ?? null }
125	              : null,
126	          },
127	        });
128	      },
129	      social_profiles_ready: (p) => {
130	        dispatchRef.current({
131	          type: "serverPatch",
132	          patch: { social_profiles: p.profiles },
133	        });
134	      },
135	      triage_ready: (p) => {
136	        dispatchRef.current({
137	          type: "serverPatch",
138	          patch: { triage_summary: p },
139	        });
140	      },
141	      todos_ready: (p) => {
142	        dispatchRef.current({
143	          type: "serverPatch",
144	          patch: { onboarding_todos: p.todos },
145	        });
146	      },
147	      workflows_ready: (p) => {
148	        dispatchRef.current({
149	          type: "serverPatch",
150	          patch: {
151	            suggested_workflows: p.workflows.map((w) => ({
152	              id: w.id ?? "",
153	              title: w.title,
154	              description: w.description ?? "",
155	              steps: (w.categories ?? []).map((c) => ({ category: c })),
156	              trigger: w.trigger,
157	            })),
158	          },
159	        });
160	      },
161	      holo_ready: () => {
162	        getPersonalization()
163	          .then((data) => {
164	            if (aborted || isRestartingRef.current) return;
165	            dispatchRef.current({ type: "serverSnapshot", data });
166	            dispatchRef.current({
167	              type: "stageComplete",
168	              stage: "holo_ready",
169	            });
170	          })
171	          .catch(() => {
172	            // swallow — WS reconnect or poll will retry
173	          });
174	      },
175	      complete: (p) => {
176	        // Backend emits `complete` only after holo_ready has fired (holo
177	        // card now runs inside the main pipeline gather), so closing the WS
178	        // here is safe — no terminal events trail this one.
179	        dispatchRef.current({
180	          type: "serverPatch",
181	          patch: {
182	            first_message_conversation_id: p.conversation_id ?? undefined,
183	            phase: "personalization_complete",
184	          },
185	        });
186	        closeWs();
187	      },
188	    };
189	
190	    /**
191	     * Calls the right handler for an envelope. Generic so TS narrows
192	     * `StagePayloads[K]` against `K` — no per-case `as` casts needed.
193	     */
194	    const dispatchEnvelope = <K extends OnboardingStage>(
195	      stage: K,
196	      payload: StagePayloads[K],
197	    ) => {
198	      handlers[stage](payload);
199	    };
200	
201	    const handleStage = (envelope: StageEnvelope) => {
202	      if (aborted) return;
203	      if (isRestartingRef.current) return;
204	
205	      // holo_ready dispatches stageComplete itself once the REST follow-up
206	      // resolves; everything else marks complete synchronously here.
207	      if (envelope.stage !== "holo_ready") {
208	        dispatchRef.current({
209	          type: "stageComplete",
210	          stage: envelope.stage,
211	        });
212	      }
213	      dispatchEnvelope(envelope.stage, envelope.payload);
214	    };
215	
216	    const flushBuffer = () => {
217	      while (buffer.length > 0) {
218	        const next = buffer.shift();
219	        if (next) handleStage(next);
220	      }
221	    };
222	
223	    const stopPoll = () => {
224	      if (pollTimer) {
225	        clearInterval(pollTimer);
226	        pollTimer = null;
227	      }
228	    };
229	
230	    const closeWs = () => {
231	      closed = true;
232	      if (reconnectTimer) {
233	        clearTimeout(reconnectTimer);
234	        reconnectTimer = null;
235	      }
236	      if (silenceTimer) {
237	        clearTimeout(silenceTimer);
238	        silenceTimer = null;
239	      }
240	      stopPoll();
241	      if (ws) {
242	        ws.close();
243	        ws = null;
244	      }
245	    };
246	
247	    const pollOnce = () => {
248	      if (closed || aborted || isRestartingRef.current) return;
249	      getPersonalization()
250	        .then((data) => {
251	          if (aborted || isRestartingRef.current) return;
252	          dispatchRef.current({ type: "serverSnapshot", data });
253	          // The snapshot fills server-side data but `completedStages` is a
254	          // session-local Set that only the WS handler populates. Backfill
255	          // it from the snapshot so the processing checklist marks rows done
256	          // even when the matching event was lost during a WS disconnect.
257	          synthesizeCompletedStages(data);
258	          if (data.first_message_conversation_id) stopPoll();
259	        })
260	        .catch(() => {
261	          // keep polling — WS may still recover
262	        });
263	    };
264	
265	    const synthesizeCompletedStages = (data: PersonalizationData): void => {
266	      // Only fire when the snapshot carries actual data — `null` and `[]`
267	      // come back on a fresh post-reset snapshot and must not be mistaken
268	      // for "the pipeline already finished this step".
269	      const fire = (stage: OnboardingStage) =>
270	        dispatchRef.current({ type: "stageComplete", stage });
271	      if (data.writing_style?.style_summary) fire("writing_style_ready");
272	      if (data.triage_summary) fire("triage_ready");
273	      if ((data.onboarding_todos?.length ?? 0) > 0) fire("todos_ready");
274	      if ((data.suggested_workflows?.length ?? 0) > 0) fire("workflows_ready");
275	      if ((data.social_profiles?.length ?? 0) > 0) {
276	        fire("social_profiles_ready");
277	      }
278	      if (data.first_message_conversation_id) fire("complete");
279	    };
280	
281	    const startPolling = () => {
282	      if (pollTimer || closed || aborted || isRestartingRef.current) return;
283	      pollOnce();
284	      pollTimer = setInterval(pollOnce, POLL_INTERVAL_MS);
285	    };
286	
287	    const runSilenceFallback = () => {
288	      if (silenceFallbackUsed) return;
289	      if (wsReceivedEvent) return;
290	      if (closed || aborted || isRestartingRef.current) return;
291	      silenceFallbackUsed = true;
292	      startPolling();
293	    };
294	
295	    const connectWs = () => {
296	      if (closed || aborted) return;
297	      try {
298	        const socket = new WebSocket(getWsUrl());
299	        ws = socket;
300	
301	        socket.onopen = () => {
302	          const isReconnect = reconnectAttempts > 0;
303	          reconnectAttempts = 0;
304	          if (isReconnect) {
305	            // Any stage event emitted during the disconnect window is gone
306	            // — close the gap with a fresh REST snapshot so the cursor can
307	            // catch up to whatever the pipeline reached while we were down.
308	            pollOnce();
309	          }
310	          if (
311	            !silenceFallbackUsed &&
312	            !wsReceivedEvent &&
313	            silenceTimer === null
314	          ) {
315	            silenceTimer = setTimeout(
316	              runSilenceFallback,
317	              WS_SILENCE_FALLBACK_MS,
318	            );
319	          }
320	        };
321	
322	        socket.onmessage = (event) => {
323	          if (aborted || isRestartingRef.current) return;
324	          wsReceivedEvent = true;
325	          if (silenceTimer) {
326	            clearTimeout(silenceTimer);
327	            silenceTimer = null;
328	          }
329	          stopPoll();
330	          try {
331	            const message = JSON.parse(event.data) as {
332	              type: string;
333	              data: unknown;
334	            };
335	            if (message.type !== "onboarding_stage") return;
336	            const envelope = message.data as StageEnvelope;
337	            console.debug("[onboarding:ws]", envelope.stage, envelope.payload);
338	            if (!snapshotResolved) {
339	              buffer.push(envelope);
340	              return;
341	            }
342	            handleStage(envelope);
343	          } catch (error) {
344	            console.error("[onboarding:ws] parse error:", error);
345	          }
346	        };
347	
348	        socket.onclose = () => {
349	          ws = null;
350	          if (closed || aborted) return;
351	          if (reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
352	            const delay =
353	              RECONNECT_BASE_DELAY_MS * 2 ** Math.min(reconnectAttempts, 5);
354	            reconnectAttempts += 1;
355	            reconnectTimer = setTimeout(connectWs, delay);
356	          }
357	        };
358	
359	        socket.onerror = () => {
360	          // onclose handles reconnect
361	        };
362	      } catch {
363	        // constructor failed
364	      }
365	    };
366	
367	    getPersonalization()
368	      .then((data) => {
369	        if (aborted) return;
370	        dispatchRef.current({ type: "serverSnapshot", data });
371	        synthesizeCompletedStages(data);
372	        snapshotResolved = true;
373	        flushBuffer();
374	      })
375	      .catch(() => {
376	        snapshotResolved = true;
377	        flushBuffer();
378	      });
379	
380	    connectWs();
381	
382	    return () => {
383	      aborted = true;
384	      closeWs();
385	    };
386	  }, [active]);
387	}
